"use client";

import React, { useEffect, useState } from "react";
import PageBreadcrumb from "@/components/common/PageBreadCrumb";
import ComponentCard from "@/components/common/ComponentCard";
import { Modal } from "@/components/ui/modal";
import Button from "@/components/ui/button/Button";
import Input from "@/components/form/input/InputField";
import Label from "@/components/form/Label";
import Badge from "@/components/ui/badge/Badge";
import { apiFetch } from "@/lib/api";
import { isSuperAdmin } from "@/lib/auth";

import {
  Table,
  TableBody,
  TableCell,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

type Customer = {
  id: string;
  full_name_ar: string;
  full_name_en?: string;
  mobile_number: string;
  national_id?: string;
  city?: string;
  address?: string;
  risk_level?: string;
  status?: string;
};

type CustomerForm = {
  full_name_ar: string;
  full_name_en: string;
  mobile_number: string;
  national_id: string;
  city: string;
  address: string;
};

const emptyForm: CustomerForm = {
  full_name_ar: "",
  full_name_en: "",
  mobile_number: "",
  national_id: "",
  city: "",
  address: "",
};

export default function CustomersPage() {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [page, setPage] = useState(1);
  const pageSize = 15;

  const [isOpen, setIsOpen] = useState(false);
  const [editingCustomer, setEditingCustomer] = useState<Customer | null>(null);
  const [superAdmin, setSuperAdmin] = useState(false);

  const [form, setForm] = useState<CustomerForm>(emptyForm);

  useEffect(() => {
    loadCustomers();
    setSuperAdmin(isSuperAdmin());
  }, []);

  async function loadCustomers() {
    try {
      setLoading(true);
      setError("");

      const data = await apiFetch("/merchant/customers");
      setCustomers(data);
    } catch (err: any) {
      setError(err.message || "Failed to load customers");
    } finally {
      setLoading(false);
    }
  }

  function openAddModal() {
    setEditingCustomer(null);
    setForm(emptyForm);
    setIsOpen(true);
  }

  function openEditModal(customer: Customer) {
    setEditingCustomer(customer);
    setForm({
      full_name_ar: customer.full_name_ar || "",
      full_name_en: customer.full_name_en || "",
      mobile_number: customer.mobile_number || "",
      national_id: customer.national_id || "",
      city: customer.city || "",
      address: customer.address || "",
    });
    setIsOpen(true);
  }

  function closeModal() {
    setIsOpen(false);
    setEditingCustomer(null);
    setForm(emptyForm);
  }

  async function saveCustomer(e: React.FormEvent) {
    e.preventDefault();

    try {
      setError("");

      if (editingCustomer) {
        await apiFetch(`/merchant/customers/${editingCustomer.id}`, {
          method: "PATCH",
          body: JSON.stringify(form),
        });
      } else {
        await apiFetch("/merchant/customers", {
          method: "POST",
          body: JSON.stringify(form),
        });
      }

      closeModal();
      await loadCustomers();
    } catch (err: any) {
      setError(err.message || "Failed to save customer");
    }
  }

  async function deactivateCustomer(id: string) {
    if (!confirm("Deactivate this customer?")) return;

    try {
      setError("");

      await apiFetch(`/merchant/customers/${id}`, {
        method: "DELETE",
      });

      await loadCustomers();
    } catch (err: any) {
      setError(err.message || "Failed to deactivate customer");
    }
  }

  const totalPages = Math.ceil(customers.length / pageSize);

  const paginatedCustomers = customers.slice(
    (page - 1) * pageSize,
    page * pageSize
  );

  return (
    <div>
      <PageBreadcrumb pageTitle="Customer" />

      <div className="space-y-6">
        <ComponentCard title="Customers">
          <div className="mb-5 flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
            <div>
              <h4 className="text-lg font-semibold text-gray-800 dark:text-white/90">
                Customer Records
              </h4>
              <p className="mt-1 text-sm text-gray-500 dark:text-gray-400">
                View, add, update and deactivate customer records.
              </p>
            </div>

            <button
              onClick={openAddModal}
              className="inline-flex items-center justify-center rounded-lg bg-brand-500 px-4 py-2.5 text-sm font-medium text-white hover:bg-brand-600"
            >
              Add Customer
            </button>
          </div>

          {error && (
            <div className="mb-5 rounded-lg border border-error-200 bg-error-50 px-4 py-3 text-sm text-error-700 dark:border-error-500/30 dark:bg-error-500/10 dark:text-error-400">
              {error}
            </div>
          )}

          <div className="overflow-hidden rounded-xl border border-gray-200 bg-white dark:border-white/[0.05] dark:bg-white/[0.03]">
            <div className="max-w-full overflow-x-auto">
              <div className="min-w-[1102px]">
                <Table>
                  <TableHeader className="border-b border-gray-100 dark:border-white/[0.05]">
                    <TableRow>
                      {[
                        "Customer",
                        "Mobile",
                        "National ID",
                        "City",
                        "Risk",
                        "Status",
                        "Actions",
                      ].map((header) => (
                        <TableCell
                          key={header}
                          isHeader
                          className="px-5 py-3 font-medium text-gray-500 text-start text-theme-xs dark:text-gray-400"
                        >
                          {header}
                        </TableCell>
                      ))}
                    </TableRow>
                  </TableHeader>

                  <TableBody className="divide-y divide-gray-100 dark:divide-white/[0.05]">
                    {loading ? (
                      <TableRow>
                        <TableCell className="px-5 py-6 text-center text-gray-500 text-theme-sm dark:text-gray-400">
                          Loading customers...
                        </TableCell>
                      </TableRow>
                    ) : paginatedCustomers.length === 0 ? (
                      <TableRow>
                        <TableCell className="px-5 py-6 text-center text-gray-500 text-theme-sm dark:text-gray-400">
                          No customers found.
                        </TableCell>
                      </TableRow>
                    ) : (
                      paginatedCustomers.map((customer) => (
                        <TableRow key={customer.id}>
                          <TableCell className="px-5 py-4 sm:px-6 text-start">
                            <div>
                              <span className="block font-medium text-gray-800 text-theme-sm dark:text-white/90">
                                {customer.full_name_ar}
                              </span>
                              <span className="block text-gray-500 text-theme-xs dark:text-gray-400">
                                {customer.full_name_en || customer.id}
                              </span>
                            </div>
                          </TableCell>

                          <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                            {customer.mobile_number}
                          </TableCell>

                          <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                            {customer.national_id || "-"}
                          </TableCell>

                          <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                            {customer.city || "-"}
                          </TableCell>

                          <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                            <Badge
                              size="sm"
                              color={
                                customer.risk_level === "low"
                                  ? "success"
                                  : customer.risk_level === "medium"
                                  ? "warning"
                                  : customer.risk_level === "high"
                                  ? "error"
                                  : "light"
                              }
                            >
                              {customer.risk_level || "unknown"}
                            </Badge>
                          </TableCell>

                          <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                            <Badge
                              size="sm"
                              color={
                                customer.status === "active"
                                  ? "success"
                                  : customer.status === "inactive"
                                  ? "error"
                                  : "warning"
                              }
                            >
                              {customer.status || "unknown"}
                            </Badge>
                          </TableCell>

                          <TableCell className="px-4 py-3 text-gray-500 text-theme-sm dark:text-gray-400">
                            <div className="flex items-center gap-2">
                              <button
                                type="button"
                                onClick={() => openEditModal(customer)}
                                className="rounded-lg border border-gray-300 px-3 py-1.5 text-sm font-medium text-gray-700 hover:bg-gray-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
                              >
                                Edit
                              </button>

                              <button
                                type="button"
                                onClick={() =>
                                  deactivateCustomer(customer.id)
                                }
                                className="rounded-lg bg-error-500 px-3 py-1.5 text-sm font-medium text-white hover:bg-error-600"
                              >
                                Deactivate
                              </button>
                            </div>
                          </TableCell>
                        </TableRow>
                      ))
                    )}
                  </TableBody>
                </Table>
              </div>
            </div>

            <div className="flex items-center justify-between border-t border-gray-100 px-5 py-4 dark:border-white/[0.05]">
              <button
                onClick={() => setPage((p) => Math.max(p - 1, 1))}
                disabled={page === 1}
                className="rounded-lg border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
              >
                Previous
              </button>

              <span className="text-sm text-gray-500 dark:text-gray-400">
                Page {page} of {totalPages || 1}
              </span>

              <button
                onClick={() => setPage((p) => Math.min(p + 1, totalPages))}
                disabled={page === totalPages || totalPages === 0}
                className="rounded-lg border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
              >
                Next
              </button>
            </div>
          </div>
        </ComponentCard>
      </div>

      <Modal isOpen={isOpen} onClose={closeModal} className="max-w-[700px] m-4">
        <div className="no-scrollbar relative w-full max-w-[700px] overflow-y-auto rounded-3xl bg-white p-4 dark:bg-gray-900 lg:p-11">
          <div className="px-2 pr-14">
            <h4 className="mb-2 text-2xl font-semibold text-gray-800 dark:text-white/90">
              {editingCustomer ? "Edit Customer" : "Add Customer"}
            </h4>

            <p className="mb-6 text-sm text-gray-500 dark:text-gray-400 lg:mb-7">
              Enter customer details below.
            </p>
          </div>

          {superAdmin && !editingCustomer && (
            <div className="mb-5 rounded-lg border border-warning-200 bg-warning-50 px-4 py-3 text-sm text-warning-700 dark:border-warning-500/30 dark:bg-warning-500/10 dark:text-warning-400">
              ⚠️ Super admin can view customers, but customer creation should
              normally be done by merchants.
            </div>
          )}

          <form onSubmit={saveCustomer} className="flex flex-col">
            <div className="custom-scrollbar max-h-[450px] overflow-y-auto px-2 pb-3">
              <h5 className="mb-5 text-lg font-medium text-gray-800 dark:text-white/90 lg:mb-6">
                Customer Information
              </h5>

              <div className="grid grid-cols-1 gap-x-6 gap-y-5 lg:grid-cols-2">
                <div>
                  <Label>Arabic Name</Label>
                  <Input
                    type="text"
                    value={form.full_name_ar}
                    onChange={(e) =>
                      setForm({ ...form, full_name_ar: e.target.value })
                    }
                    required
                  />
                </div>

                <div>
                  <Label>English Name</Label>
                  <Input
                    type="text"
                    value={form.full_name_en}
                    onChange={(e) =>
                      setForm({ ...form, full_name_en: e.target.value })
                    }
                  />
                </div>

                <div>
                  <Label>Mobile</Label>
                  <Input
                    type="text"
                    value={form.mobile_number}
                    onChange={(e) =>
                      setForm({ ...form, mobile_number: e.target.value })
                    }
                    required
                  />
                </div>

                <div>
                  <Label>National ID</Label>
                  <Input
                    type="text"
                    value={form.national_id}
                    onChange={(e) =>
                      setForm({ ...form, national_id: e.target.value })
                    }
                  />
                </div>

                <div>
                  <Label>City</Label>
                  <Input
                    type="text"
                    value={form.city}
                    onChange={(e) =>
                      setForm({ ...form, city: e.target.value })
                    }
                  />
                </div>

                <div>
                  <Label>Address</Label>
                  <Input
                    type="text"
                    value={form.address}
                    onChange={(e) =>
                      setForm({ ...form, address: e.target.value })
                    }
                  />
                </div>
              </div>
            </div>

            <div className="flex items-center gap-3 px-2 mt-6 lg:justify-end">
              <Button
                size="sm"
                variant="outline"
                type="button"
                onClick={closeModal}
              >
                Close
              </Button>

              <Button size="sm" type="submit">
                {editingCustomer ? "Save Changes" : "Add Customer"}
              </Button>
            </div>
          </form>
        </div>
      </Modal>
    </div>
  );
}